import { Request, Response } from 'express';
import { TaskService } from '../services/tasks';
import { logger } from '../utils/logger';

const taskService = new TaskService();

export const getAllTasks = async (req: Request, res: Response) => {
  try {
    const tasks = await taskService.getAllTasks();
    logger.info('Successfully fetched all tasks');
    res.json({
      code: 0,
      msg: 'success',
      data: tasks,
      trace_id: req.headers['x-request-id'] || 'default',
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to fetch all tasks', error as Error);
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: req.headers['x-request-id'] || 'default',
      timestamp: new Date().toISOString()
    });
  }
};

export const getTaskById = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { id } = req.params;
  try {
    logger.info('Fetching task by ID', { requestId, taskId: id });
    const task = await taskService.getTaskById(id);
    if (!task) {
      logger.warn(`Task not found with ID: ${id}`, { requestId, taskId: id });
      return res.status(404).json({
        code: 404,
        msg: 'Task not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }
    logger.info('Successfully fetched task', { requestId, taskId: id });
    res.json({
      code: 0,
      msg: 'success',
      data: task,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to fetch task', error as Error, { requestId, taskId: id });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const createTask = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  try {
    logger.info('Creating new task', { requestId, body: req.body });
    const task = await taskService.createTask(req.body);
    logger.info('Task created successfully', { requestId, taskId: task.id });
    res.json({
      code: 0,
      msg: 'Task created successfully',
      data: task,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to create task', error as Error, { requestId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const updateTask = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { id } = req.params;
  try {
    logger.info('Updating task', { requestId, taskId: id, body: req.body });
    const task = await taskService.updateTask(id, req.body);
    if (!task) {
      logger.warn(`Task not found for update with ID: ${id}`, { requestId, taskId: id });
      return res.status(404).json({
        code: 404,
        msg: 'Task not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }
    logger.info('Task updated successfully', { requestId, taskId: id });
    res.json({
      code: 0,
      msg: 'Task updated successfully',
      data: task,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to update task', error as Error, { requestId, taskId: id });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const deleteTask = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { id } = req.params;
  try {
    logger.info('Deleting task', { requestId, taskId: id });
    await taskService.deleteTask(id);
    logger.info('Task deleted successfully', { requestId, taskId: id });
    res.json({
      code: 0,
      msg: 'Task deleted successfully',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to delete task', error as Error, { requestId, taskId: id });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const getTasksByProject = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { projectId } = req.params;
  try {
    logger.info('Fetching tasks by project', { requestId, projectId });
    const tasks = await taskService.getTasksByProject(projectId);
    logger.info('Tasks by project fetched', { requestId, projectId, count: tasks.length });
    res.json({
      code: 0,
      msg: 'Success',
      data: tasks,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to fetch tasks by project', error as Error, { requestId, projectId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const updateTaskStatus = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { id } = req.params;
  try {
    logger.info('Updating task status', { requestId, taskId: id, status: req.body.status });
    const task = await taskService.updateTaskStatus(
      req.params.id as string, 
      req.body.status
    );
    logger.info('Task status updated', { requestId, taskId: id });
    res.json({
      code: 0,
      msg: 'Task status updated successfully',
      data: task,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to update task status', error as Error, { requestId, taskId: id });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const assignTask = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { id } = req.params;
  const { assignee_agent_id } = req.body;
  try {
    logger.info('Assigning task', { requestId, taskId: id, assignee: assignee_agent_id });
    const task = await taskService.assignTask(id, assignee_agent_id);
    logger.info('Task assigned', { requestId, taskId: id, assignee: assignee_agent_id });
    res.json({
      code: 0,
      msg: 'Task assigned successfully',
      data: task,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to assign task', error as Error, { requestId, taskId: id });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const acceptTask = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const taskId = req.params.id as string;
  const { result, comment } = req.body;

  try {
    logger.info('Accepting task', { requestId, taskId, result });
    const task = await taskService.acceptTask(taskId, result, comment);
    logger.info('Task accepted successfully', { requestId, taskId, result });
    res.json({
