      code: 0,
      msg: 'API key created successfully',
      data: {
        api_key, // Only returned once at creation
        id: api_key_record.id,
        expires_at: api_key_record.expires_at
      },
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
