import bcrypt from 'bcrypt';
import { ApiKey } from '../models/ApiKey';
import { randomBytes } from 'crypto';

export class ApiKeyService {
  /**
   * List all API keys for an agent
   */
  async listApiKeys(agentId: string): Promise<ApiKey[]> {
    return ApiKey.findAll({
      where: { agent_id: agentId },
      order: [['created_at', 'DESC']],
      attributes: ['id', 'agent_id', 'created_at', 'expires_at', 'revoked_at', 'is_active']
    });
  }

  /**
   * Create a new API key
   * Returns the plain text key only once at creation
   */
  async createApiKey(
    agentId: string,
    expiresInDays: number = 90
  ): Promise<{ api_key: string; api_key_record: ApiKey }> {
    // Generate random API key
    const plainKey = `ak_${randomBytes(32).toString('hex')}`;

    // Hash the key for storage
    const salt = bcrypt.genSaltSync(10);
    const keyHash = bcrypt.hashSync(plainKey, salt);

    // Calculate expiration
    const createdAt = new Date();
    const expiresAt = new Date(createdAt.getTime() + expiresInDays * 24 * 60 * 60 * 1000);

    // Create record
    const apiKeyRecord = await ApiKey.create({
      agent_id: agentId,
      key_hash: keyHash,
      salt,
      created_at: createdAt,
      expires_at: expiresAt,
      revoked_at: null,
      is_active: true
    });

    return {
      api_key: plainKey,
      api_key_record: apiKeyRecord
    };
  }

  /**
   * Revoke an API key immediately
   */
  async revokeApiKey(id: string): Promise<ApiKey | null> {
    const apiKey = await ApiKey.findByPk(id);
    if (!apiKey) {
      return null;
    }

    await apiKey.update({
      revoked_at: new Date(),
      is_active: false
    });

    return apiKey;
  }

  /**
   * Rotate an API key - create new key, keep old key active for 24 hours
   */
  async rotateApiKey(
    oldId: string,
    expiresInDays: number = 90
  ): Promise<{ new_api_key: string; new_api_key_record: ApiKey }> {
    // Get old key
    const oldKey = await ApiKey.findByPk(oldId);
    if (!oldKey) {
      throw new Error('Old API key not found');
    }

    // Get agent id from old key
    const agentId = oldKey.agent_id;

    // Revoke old key after 24h transition period
    const newExpiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000);
    await oldKey.update({ expires_at: newExpiresAt });

    // Create new key
    const result = await this.createApiKey(agentId, expiresInDays);
    return {
      new_api_key: result.api_key,
      new_api_key_record: result.api_key_record
    };
  }

  /**
   * Verify an API key
   * @returns agentId if valid, null if invalid
   */
  async verifyApiKey(plainKey: string): Promise<string | null> {
    // Verify by hashing and comparing
    const apiKeys = await ApiKey.findAll({ where: { is_active: true } });

    for (const apiKey of apiKeys) {
      const match = bcrypt.compareSync(plainKey, apiKey.key_hash);
      if (match) {
        // Check if expired
        if (apiKey.expires_at && new Date() > apiKey.expires_at) {
          await apiKey.update({ is_active: false });
          return null;
        }
        // Check if revoked
        if (apiKey.revoked_at) {
          return null;
        }
        return apiKey.agent_id;
      }
    }

    return null;
  }
}

