import { Request, Response } from 'express';
import { ProjectService } from '../services/projects';
import { validateUpdateProject } from '../utils/validation';
import { logger } from '../utils/logger';
import { eventEmitter } from '../events/eventEmitter';

const projectService = new ProjectService();

export const getAllProjects = async (req: Request, res: Response) => {
  try {
    const projects = await projectService.getAllProjects();
    logger.info('Successfully fetched all projects');
    res.json({
      code: 0,
      msg: 'success',
      data: projects,
      trace_id: req.headers['x-request-id'] || 'default',
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to fetch all projects', error as Error);
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: req.headers['x-request-id'] || 'default',
      timestamp: new Date().toISOString()
    });
  }
};

export const getProjectById = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { id } = req.params;
  try {
    logger.info('Fetching project by ID', { requestId, projectId: id });
    const project = await projectService.getProjectById(id);
    if (!project) {
      logger.warn(`Project not found with ID: ${id}`, { requestId, projectId: id });
      return res.status(404).json({
        code: 404,
        msg: 'Project not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }
    logger.info('Successfully fetched project', { requestId, projectId: id });
    res.json({
      code: 0,
      msg: 'success',
      data: project,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to fetch project', error as Error, { requestId, projectId: id });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const createProject = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  try {
    logger.info('Creating new project', { requestId, body: req.body });
    const project = await projectService.createProject(req.body);
    logger.info('Project created successfully', { requestId, projectId: project.id });

    // Add audit log
    await addAuditLog(req, 'create', 'project', project.id);

    // Trigger event
    eventEmitter.emit('project_created', {
      project_id: project.id,
      created_by: (req as any).user?.id,
      created_at: new Date().toISOString()
    });

    res.json({
      code: 0,
      msg: 'Project created successfully',
      data: project,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to create project', error as Error, { requestId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const updateProject = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const projectId = req.params.id as string;
  try {
    logger.info('Updating project', { requestId, projectId, body: req.body });

    // 验证请求数据
    const validation = validateUpdateProject(req.body);
    if (!validation.valid) {
      logger.warn('Project update validation failed', { requestId, projectId, errors: validation.errors });
      return res.status(400).json({
        code: 400,
        msg: validation.errors.join(', '),
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    // 权限校验：只有项目负责人或系统管理员可以修改项目配置
    const currentUserId = (req as any).user?.id;
    if (!currentUserId) {
      return res.status(401).json({
        code: 401,
        msg: 'Authentication required',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    // 检查用户权限（项目负责人或管理员）
    const canUpdate = await projectService.checkUpdatePermission(projectId, currentUserId, (req as any).user?.role);
    if (!canUpdate) {
      return res.status(403).json({
        code: 403,
        msg: 'Only project manager or system administrator can update project configuration',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    const project = await projectService.updateProject(projectId, req.body);

    if (!project) {
      logger.warn(`Project not found for update with ID: ${projectId}`, { requestId, projectId });
      return res.status(404).json({
        code: 404,
        msg: 'Project not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    // 触发 project_config_updated 事件推送
    eventEmitter.emit('project_config_updated', {
      project_id: projectId,
      updates: req.body,
      updated_by: (req as any).user?.id,
      updated_at: new Date().toISOString()
    });
    addAuditLog(req, 'update_config', 'project', projectId);

    logger.info('Project updated successfully', { requestId, projectId });
    res.json({
      code: 0,
      msg: 'Project updated successfully',
      data: project,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to update project', error as Error, { requestId, projectId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const deleteProject = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { id } = req.params;
  try {
    logger.info('Deleting project', { requestId, projectId: id });
    await projectService.deleteProject(id);

    addAuditLog(req, 'delete', 'project', id);
    eventEmitter.emit('project_deleted', {
      project_id: id,
      deleted_by: (req as any).user?.id,
      deleted_at: new Date().toISOString()
    });

    logger.info('Project deleted successfully', { requestId, projectId: id });
    res.json({
      code: 0,
      msg: 'Project deleted successfully',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to delete project', error as Error, { requestId, projectId: id });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const archiveProject = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const projectId = req.params.id as string;
  try {
    logger.info('Archiving project', { requestId, projectId });

    // 权限校验：只有项目负责人或系统管理员可以归档项目
    const currentUserId = (req as any).user?.id;
    if (!currentUserId) {
      return res.status(401).json({
        code: 401,
        msg: 'Authentication required',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    const canArchive = await projectService.checkUpdatePermission(projectId, currentUserId, (req as any).user?.role);
    if (!canArchive) {
      return res.status(403).json({
        code: 403,
        msg: 'Only project manager or system administrator can archive project',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    await projectService.archiveProject(projectId);

    // 触发 project_archived 事件推送
    eventEmitter.emit('project_archived', {
      project_id: projectId,
      archived_by: currentUserId,
      archived_at: new Date().toISOString()
    });

    // Add audit log
    await addAuditLog(req, 'archive', 'project', projectId);

    logger.info('Project archived successfully', { requestId, projectId });
    res.json({
      code: 0,
      msg: 'Project archived successfully',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to archive project', error as Error, { requestId, projectId });
