export const retryAllDeadLetters = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';

  try {
    logger.info('Retrying all dead letter events', { requestId });
    const deadLetters = await DeadLetterEvent.findAll();
    let retried = 0;

    for (const dl of deadLetters) {
      const subscription = await subscriptionService.getSubscriptionById(dl.subscription_id);
      if (subscription && subscription.status === 'active') {
        eventEmitter.emit(dl.event_type, dl.event_payload);
        retried++;
      }
      await dl.destroy();
    }

    logger.info('All dead letter events retried', { requestId, retried });
    res.json({
      code: 0,
      msg: `Retried ${retried} dead letter events`,
      data: { retried },
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to retry all dead letters', error as Error, { requestId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

/**
 * 删除死信事件
 */
export const deleteDeadLetter = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { id } = req.params;

