    res.json({
      code: 0,
      msg: 'Dead letter event deleted successfully',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to delete dead letter', error as Error, { requestId, id });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

