import { useState, useEffect } from 'react';
import { Card, Statistic, Button, Space } from 'antd';
import {
  ProjectOutlined,
  WarningOutlined,
  ClockCircleOutlined,
  FilterOutlined,
  RestOutlined,
  ExportOutlined,
  CheckCircleOutlined,
} from '@ant-design/icons';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { BarChart, Bar, Cell } from 'recharts';
import { statisticsApi } from '../../services/api';
import type { Statistics } from '../../types';

// 模拟数据
const mockProjectTrend = [
  { date: '01', value: 5 },
  { date: '02', value: 8 },
  { date: '03', value: 12 },
  { date: '04', value: 15 },
  { date: '05', value: 18 },
  { date: '06', value: 22 },
  { date: '07', value: 25 },
];

const mockAgentWorkload = [
  { name: '开发Agent', type: 'development', tasks: 15 },
  { name: '测试Agent', type: 'testing', tasks: 8 },
  { name: '产品Agent', type: 'product', tasks: 6 },
  { name: '管理Agent', type: 'management', tasks: 3 },
];

const COLORS = ['#1890ff', '#52c41a', '#faad14', '#f5222d'];

export const Analytics: React.FC = () => {
  const [statistics, setStatistics] = useState<Statistics | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        const response = await statisticsApi.getStatistics();
        if (response.code === 0) {
          setStatistics(response.data);
        } else {
          console.error('获取统计数据失败:', response.msg);
          // 使用模拟数据
          setStatistics({
            activeProjects: 35,
            pendingReviewTasks: 22,
            blockedTasks: 12,
            averageDeliveryTime: 5.2,
            projectTrend: mockProjectTrend,
            agentWorkload: mockAgentWorkload,
            taskStatusDistribution: [],
            projectEfficiency: [],
          });
        }
      } catch (error) {
        console.error('获取统计数据失败:', error);
        // 使用模拟数据
        setStatistics({
          activeProjects: 35,
          pendingReviewTasks: 22,
          blockedTasks: 12,
          averageDeliveryTime: 5.2,
          projectTrend: mockProjectTrend,
          agentWorkload: mockAgentWorkload,
          taskStatusDistribution: [],
          projectEfficiency: [],
        });
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  if (loading) {
    return (
      <div style={{ textAlign: 'center', padding: '100px 0' }}>
        加载中...
      </div>
    );
  }

  return (
    <div>
      <div className="tw-flex tw-flex-col tw-gap-4 sm:tw-flex-row sm:tw-justify-between sm:tw-items-center tw-mb-6">
        <h2 className="tw-m-0 tw-text-xl sm:tw-text-2xl tw-font-bold">
          统计分析
        </h2>
        <Space className="tw-w-full sm:tw-w-auto">
          <Button icon={<FilterOutlined />} className="tw-w-full sm:tw-w-auto tw-min-h-[48px] sm:tw-min-w-[48px] tw-px-4">筛选时间</Button>
          <Button icon={<RestOutlined />} onClick={() => window.location.reload()} className="tw-w-full sm:tw-w-auto tw-min-h-[48px] sm:tw-min-w-[48px] tw-px-4">
            刷新

