import { AgentApiKeys } from '../pages/AgentApiKeys';
import { CrossProjectStats } from '../pages/CrossProjectStats';
import NotFound from '../pages/NotFound';

const router = createBrowserRouter([
  {
    path: '/',
    element: <App />,
    children: [
      {
        index: true,
        element: <Dashboard />,
      },
      {
        path: '/projects',
        element: <ProjectList />,
      },
      {
        path: '/projects/:id',
        element: <ProjectDetail />,
      },
      {
        path: '/projects/:id/config',
        element: <ProjectConfig />,
      },
      {
        path: '/projects/:id/statistics',
        element: <ProjectStatistics />,
      },
      {
        path: '/tasks',
        element: <TaskList />,
      },
      {
        path: '/tasks/:id',
        element: <TaskDetail />,
      },
      {
        path: '/statistics',
        element: <Analytics />,
      },
      {
        path: '/statistics/cross-project',
        element: <CrossProjectStats />,
      },
      {
        path: '/audit',
        element: <AuditLogs />,
      },
      {
        path: '/admin/subscriptions/dead-letters',
        element: <DeadLetterManagement />,
      },
      {
        path: '/admin/agents/:id/api-keys',
        element: <AgentApiKeys />,
      },
      {
        path: '*',
        element: <NotFound />,
      },
    ],
  },
]);

export default router;

